    40→// ExecuteRecipes executes OpenRewrite recipes using the ARF system
    41→func (e *ARFRecipeExecutor) ExecuteRecipes(ctx context.Context, workspacePath string, recipeIDs []string) error {
    42→	// For MVP, we'll invoke the ploy arf command directly
    43→	// This reuses the existing ARF pipeline without duplicating logic
    44→
    45→	// Get current executable path to avoid PATH dependency issues
    46→	execPath, err := os.Executable()
    47→	if err != nil {
    48→		return fmt.Errorf("failed to get current executable path: %w", err)
    49→	}
    50→
    51→	for _, recipeID := range recipeIDs {
    52→		args := []string{"arf", "recipes", "transform", "--recipe", recipeID}
    53→		if e.controllerURL != "" {
    54→			args = append(args, "--controller", e.controllerURL)
    55→		}
    56→
    57→		// Execute ploy arf transform command using full executable path
    58→		cmd := exec.CommandContext(ctx, execPath, args...)
    59→		cmd.Dir = workspacePath
    60→
    61→		if err := cmd.Run(); err != nil {
    62→			return fmt.Errorf("failed to execute recipe %s: %w", recipeID, err)
    63→		}
    64→	}
    65→
    66→	return nil
    67→}
