    81→// CheckBuild performs a build check using the existing SharedPush infrastructure
    82→func (b *SharedPushBuildChecker) CheckBuild(ctx context.Context, config common.DeployConfig) (*common.DeployResult, error) {
    83→	// Set the controller URL in the config
    84→	config.ControllerURL = b.controllerURL
    85→	config.IsPlatform = false // transflow uses ploy mode, not ployman mode
    86→
    87→	// Use SharedPush to perform the build check
    88→	// SharedPush already supports build-only mode when used with specific endpoints
    89→	result, err := common.SharedPush(config)
    90→	if err != nil {
    91→		return nil, fmt.Errorf("build check failed: %w", err)
    92→	}
    93→
    94→	return result, nil
    95→}
