   184→// CreateKBIntegration creates a KB integration for learning from healing attempts
   185→func (i *TransflowIntegrations) CreateKBIntegration() KBIntegrator {
   186→	if i.TestMode {
   187→		// Return mock KB integration for testing
   188→		return NewMockKBIntegration()
   189→	}
   190→
   191→	// Create production KB integration
   192→	storageConfig := storage.Config{
   193→		Master:      "localhost:9333", // Default SeaweedFS master
   194→		Filer:       "localhost:8888", // Default SeaweedFS filer
   195→		Collection:  "kb",
   196→		Replication: "000", // No replication for development
   197→		Timeout:     30,
   198→	}
   199→
   200→	storageClient, err := storage.New(storageConfig)
   201→	if err != nil {
   202→		// If storage creation fails, use a mock KB integration to prevent breaking the workflow
   203→		return NewMockKBIntegration()
   204→	}
   205→
   206→	// Adapt StorageProvider to Storage interface
   207→	storageBackend := storage.NewStorageAdapter(storageClient)
   208→
   209→	kvStore := orchestration.NewKV()
   210→
   211→	kbConfig := DefaultKBConfig()
   212→	return NewKBIntegration(storageBackend, kvStore, kbConfig)
   213→}
